  <div class="control-group">
    <button class="btn-clear" onclick="clearList()">✕ Clear All</button>
  </div>
</div>

<div class="canvas-wrapper">
  <div class="list-container" id="listContainer">
    <div class="empty-msg" id="emptyMsg">The list is empty.<br/>Use the controls above to add nodes.</div>
  </div>
</div>

<div class="message-bar msg-hidden" id="messageBar"></div>
<div class="stats">Nodes: <span id="nodeCount">0</span></div>

<script>
  // ─── Data Model ───────────────────────────────────────────────────────────
  class ListNode {
    constructor(val) {
      this.val = val;
      this.next = null;
      this.id = 'node_' + Date.now() + '_' + Math.random().toString(36).slice(2, 7);
    }
  }

  class LinkedList {
    constructor() { this.head = null; this.size = 0; }

    insertHead(val) {
      const n = new ListNode(val);
      n.next = this.head;
      this.head = n;
      this.size++;
      return n.id;
    }

    insertTail(val) {
      const n = new ListNode(val);
      if (!this.head) { this.head = n; this.size++; return n.id; }
      let cur = this.head;
      while (cur.next) cur = cur.next;
      cur.next = n;
      this.size++;
      return n.id;
    }

    delete(val) {
      if (!this.head) return false;
      if (this.head.val === val) {
        this.head = this.head.next;
        this.size--;
        return true;
      }
      let cur = this.head;
      while (cur.next) {
        if (cur.next.val === val) {
          cur.next = cur.next.next;
          this.size--;
          return true;
        }
        cur = cur.next;
      }
      return false;
    }

    search(val) {
      let cur = this.head, idx = 0;
      while (cur) {
        if (cur.val === val) return { node: cur, index: idx };
        cur = cur.next;
        idx++;
      }
      return null;
    }

    toArray() {
      const arr = [];
      let cur = this.head;
      while (cur) { arr.push(cur); cur = cur.next; }
      return arr;
    }
  }

  // ─── State ────────────────────────────────────────────────────────────────
  const ll = new LinkedList();
  let msgTimeout = null;

  // ─── Rendering ────────────────────────────────────────────────────────────
  function render(highlightId = null) {
    const container = document.getElementById('listContainer');
    const nodes = ll.toArray();

    container.innerHTML = '';

    if (nodes.length === 0) {
      const msg = document.createElement('div');
      msg.className = 'empty-msg';
      msg.id = 'emptyMsg';
      msg.innerHTML = 'The list is empty.<br/>Use the controls above to add nodes.';
      container.appendChild(msg);
      document.getElementById('nodeCount').textContent = '0';
      return;
    }

    nodes.forEach((node, i) => {
      // Node wrapper
      const wrapper = document.createElement('div');
      wrapper.className = 'node-wrapper';
      wrapper.id = 'wrapper_' + node.id;

      // Outer (for label)
      const outer = document.createElement('div');
      outer.className = 'node-box-outer';

      // Label (HEAD / TAIL)
      if (i === 0 || i === nodes.length - 1) {
        const lbl = document.createElement('div');
        lbl.className = 'node-label';
        if (i === 0 && nodes.length === 1) lbl.textContent = 'HEAD / TAIL';
        else if (i === 0) lbl.textContent = 'HEAD';
        else lbl.textContent = 'TAIL';
        outer.appendChild(lbl);
      }

      // Node box
      const box = document.createElement('div');
      box.className = 'node-box';
      if (i === 0) box.classList.add('head-node');
      if (i === nodes.length - 1) box.classList.add('tail-node');
      if (node.id === highlightId) box.classList.add('highlighted');

      const valDiv = document.createElement('div');
      valDiv.className = 'node-value';
      valDiv.textContent = node.val;

      const nextDiv = document.createElement('div');
      nextDiv.className = 'node-next';
      nextDiv.textContent = node.next ? `→ next` : `→ null`;

      box.appendChild(valDiv);
      box.appendChild(nextDiv);
      outer.appendChild(box);
      wrapper.appendChild(outer);

      // Arrow (between nodes)
      if (i < nodes.length - 1) {
        const arrowWrap = document.createElement('div');
        arrowWrap.className = 'arrow';
        const line = document.createElement('div');
        line.className = 'arrow-line';
        arrowWrap.appendChild(line);
        wrapper.appendChild(arrowWrap);
      }

      container.appendChild(wrapper);
    });

    // NULL terminator
    const arrowToNull = document.createElement('div');
    arrowToNull.className = 'arrow';
    const line2 = document.createElement('div');
    line2.className = 'arrow-line';
    arrowToNull.appendChild(line2);
    container.appendChild(arrowToNull);

    const nullBox = document.createElement('div');
    nullBox.className = 'null-box';
    nullBox.textContent = 'NULL';
    container.appendChild(nullBox);

    document.getElementById('nodeCount').textContent = ll.size;
  }

  // ─── Message Helper ───────────────────────────────────────────────────────
  function showMessage(text, type = 'info', duration = 3000) {
    const bar = document.getElementById('messageBar');
    bar.textContent = text;
    bar.className = 'message-bar msg-' + type;
    if (msgTimeout) clearTimeout(msgTimeout);
    msgTimeout = setTimeout(() => {
      bar.className = 'message-bar msg-hidden';
    }, duration);
  }

  // ─── Input Helper ─────────────────────────────────────────────────────────
  function getVal(id) {
    const v = document.getElementById(id).value.trim();
    if (v === '') return null;
    const n = parseInt(v, 10);
    return isNaN(n) ? null : n;
  }

  function clearInput(id) {
    document.getElementById(id).value = '';
  }

  // ─── Operations ───────────────────────────────────────────────────────────
  function insertHead() {
    const val = getVal('headVal');
    if (val === null) { showMessage('Please enter a valid integer value.', 'error'); return; }
    ll.insertHead(val);
    clearInput('headVal');
    render();
    showMessage(`✔ Inserted ${val} at the head.`, 'success');
  }

  function insertTail() {
    const val = getVal('tailVal');
    if (val === null) { showMessage('Please enter a valid integer value.', 'error'); return; }
    ll.insertTail(val);
    clearInput('tailVal');
    render();
    showMessage(`✔ Inserted ${val} at the tail.`, 'success');
  }

  function deleteNode() {
    const val = getVal('deleteVal');
    if (val === null) { showMessage('Please enter a valid integer value.', 'error'); return; }
    if (ll.size === 0) { showMessage('The list is already empty.', 'error'); return; }
    const deleted = ll.delete(val);
    clearInput('deleteVal');
    render();
    if (deleted) showMessage(`🗑 Deleted node with value ${val}.`, 'success');
    else showMessage(`⚠ Value ${val} not found in the list.`, 'error');
  }

  function searchNode() {
    const val = getVal('searchVal');
    if (val === null) { showMessage('Please enter a valid integer value.', 'error'); return; }
    if (ll.size === 0) { showMessage('The list is empty — nothing to search.', 'error'); return; }
    const result = ll.search(val);
    clearInput('searchVal');
    if (result) {
      render(result.node.id);
      showMessage(`🔍 Found ${val} at index ${result.index}!`, 'found', 4000);
    } else {
      render();
      showMessage(`⚠ Value ${val} was not found in the list.`, 'error');
    }
  }

  function clearList() {
    ll.head = null;
    ll.size = 0;
    render();
    showMessage('List cleared.', 'info');
  }

  // ─── Keyboard Shortcuts ───────────────────────────────────────────────────
  document.getElementById('headVal').addEventListener('keydown',   e => { if (e.key === 'Enter') insertHead(); });
  document.getElementById('tailVal').addEventListener('keydown',   e => { if (e.key === 'Enter') insertTail(); });
  document.getElementById('deleteVal').addEventListener('keydown', e => { if (e.key === 'Enter') deleteNode(); });
  document.getElementById('searchVal').addEventListener('keydown', e => { if (e.key === 'Enter') searchNode(); });

  // ─── Initial Render ───────────────────────────────────────────────────────
  render();

  // Seed a few demo nodes so it's not empty on load
  [10, 25, 37, 52].forEach(v => ll.insertTail(v));
  render();
  showMessage('👋 Demo list loaded! Try inserting, deleting, or searching.', 'info', 5000);
</script>
</body>
</html>
```

---

Here's a breakdown of what's included:

### Features
| Feature | Details |
|---|---|
| **Insert at Head** | Prepends a node with animation |
| **Insert at Tail** | Appends a node with animation |
| **Delete by Value** | Removes first match, reports if not found |
| **Search** | Highlights found node in gold with a glow effect |
| **Clear All** | Resets the list gracefully |
| **Empty State** | Friendly placeholder message when list is empty |
| **Keyboard Support** | Press `Enter` in any input to trigger its action |
| **Demo Seed** | Starts with 4 nodes so you can explore immediately |

### Visual Details
- **HEAD** node has a red border, **TAIL** has a green border
- Arrow lines with arrowheads connect each node
- A `NULL` terminator box ends the list
- Found nodes pulse with a **gold glow**
- Nodes animate in with a spring-like bounce on insertion
- Color-coded message bar for success / error / search results

