</head>
<body>

<h1>⛓ Singly Linked List</h1>
<p class="subtitle">Visualize and interact with a singly linked list in real time</p>

<div class="controls">
    <div class="control-group">
        <label>Value:</label>
        <input type="text" id="insertInput" placeholder="e.g. 42" maxlength="6" />
    </div>
    <button class="btn-insert-head" onclick="insertHead()">⬅ Insert Head</button>
    <button class="btn-insert-tail" onclick="insertTail()">Insert Tail ➡</button>

    <div class="divider"></div>

    <div class="control-group">
        <label>Delete:</label>
        <input type="text" id="deleteInput" placeholder="value" maxlength="6" />
    </div>
    <button class="btn-delete" onclick="deleteNode()">🗑 Delete</button>

    <div class="divider"></div>

    <div class="control-group">
        <label>Search:</label>
        <input type="text" id="searchInput" placeholder="value" maxlength="6" />
    </div>
    <button class="btn-search" onclick="searchNode()">🔍 Search</button>

    <div class="divider"></div>

    <button class="btn-clear" onclick="clearList()">✕ Clear</button>
</div>

<div class="message-box" id="messageBox">Ready — insert a node to get started!</div>

<div class="canvas-wrapper">
    <div class="list-container" id="listContainer"></div>
</div>

<div class="stats-bar">
    <div class="stat">Size: <span id="statSize">0</span></div>
    <div class="stat">Head: <span id="statHead">—</span></div>
    <div class="stat">Tail: <span id="statTail">—</span></div>
</div>

<div class="legend">
    <div class="legend-item"><div class="legend-dot head"></div> Head</div>
    <div class="legend-item"><div class="legend-dot tail"></div> Tail</div>
    <div class="legend-item"><div class="legend-dot both"></div> Head & Tail</div>
    <div class="legend-item"><div class="legend-dot found"></div> Found / Highlighted</div>
</div>

<script>
    // ─── Data Structure ───────────────────────────────────────────────────────

    class ListNode {
        constructor(value) {
            this.value = value;
            this.next  = null;
        }
    }

    class SinglyLinkedList {
        constructor() {
            this.head = null;
            this.size = 0;
        }

        insertHead(value) {
            const node = new ListNode(value);
            node.next  = this.head;
            this.head  = node;
            this.size++;
        }

        insertTail(value) {
            const node = new ListNode(value);
            if (!this.head) {
                this.head = node;
            } else {
                let cur = this.head;
                while (cur.next) cur = cur.next;
                cur.next = node;
            }
            this.size++;
        }

        // Returns true if deleted, false if not found
        delete(value) {
            if (!this.head) return false;
            if (this.head.value == value) {
                this.head = this.head.next;
                this.size--;
                return true;
            }
            let cur = this.head;
            while (cur.next) {
                if (cur.next.value == value) {
                    cur.next = cur.next.next;
                    this.size--;
                    return true;
                }
                cur = cur.next;
            }
            return false;
        }

        // Returns 0-based index or -1
        search(value) {
            let cur = this.head, idx = 0;
            while (cur) {
                if (cur.value == value) return idx;
                cur = cur.next;
                idx++;
            }
            return -1;
        }

        toArray() {
            const arr = [];
            let cur = this.head;
            while (cur) { arr.push(cur.value); cur = cur.next; }
            return arr;
        }

        getTail() {
            if (!this.head) return null;
            let cur = this.head;
            while (cur.next) cur = cur.next;
            return cur.value;
        }

        clear() {
            this.head = null;
            this.size = 0;
        }
    }

    // ─── State ────────────────────────────────────────────────────────────────

    const ll = new SinglyLinkedList();
    let highlightedIndex = -1;
    let messageTimer     = null;

    // ─── UI Helpers ───────────────────────────────────────────────────────────

    function showMessage(text, type = 'info') {
        const box = document.getElementById('messageBox');
        box.textContent  = text;
        box.className    = `message-box ${type}`;
        clearTimeout(messageTimer);
        messageTimer = setTimeout(() => {
            box.textContent = '';
            box.className   = 'message-box';
        }, 3000);
    }

    function getInput(id) {
        const el  = document.getElementById(id);
        const val = el.value.trim();
        el.value  = '';
        return val;
    }

    function updateStats() {
        document.getElementById('statSize').textContent = ll.size;
        document.getElementById('statHead').textContent = ll.head ? ll.head.value : '—';
        document.getElementById('statTail').textContent = ll.size > 0 ? ll.getTail() : '—';
    }

    // ─── Render ───────────────────────────────────────────────────────────────

    function render(highlightIdx = -1) {
        const container = document.getElementById('listContainer');
        container.innerHTML = '';

        const arr = ll.toArray();

        if (arr.length === 0) {
            container.innerHTML = `
                <div class="empty-state">
                    <div class="empty-icon">🔗</div>
                    <p>The list is empty — insert a node to begin!</p>
                </div>`;
            updateStats();
            return;
        }

        arr.forEach((val, i) => {
            // Node wrapper
            const wrapper = document.createElement('div');
            wrapper.className = 'node-wrapper';

            // Node box
            const node = document.createElement('div');
            node.className = 'node';

            const isHead = i === 0;
            const isTail = i === arr.length - 1;
            if (isHead && isTail) node.classList.add('head-node', 'tail-node');
            else if (isHead)      node.classList.add('head-node');
            else if (isTail)      node.classList.add('tail-node');

            if (i === highlightIdx) node.classList.add('highlighted');

            // Label
            let labelText = '';
            if (isHead && isTail) labelText = 'HEAD · TAIL';
            else if (isHead)      labelText = 'HEAD';
            else if (isTail)      labelText = 'TAIL';

            node.innerHTML = `
                ${labelText ? `<div class="node-label">${labelText}</div>` : ''}
                <div class="node-value">${val}</div>
                <div class="node-index">[${i}]</div>
            `;

            wrapper.appendChild(node);

            // Arrow between nodes
            if (i < arr.length - 1) {
                const arrow = document.createElement('div');
                arrow.className = 'arrow';
                arrow.textContent = '→';
                wrapper.appendChild(arrow);
            }

            container.appendChild(wrapper);
        });

        // NULL terminator
        const nullWrapper = document.createElement('div');
        nullWrapper.className = 'node-wrapper';
        nullWrapper.innerHTML = `
            <div class="arrow">→</div>
            <div class="null-node">
                <div class="null-box">null</div>
            </div>
        `;
        container.appendChild(nullWrapper);

        updateStats();
    }

    // ─── Actions ──────────────────────────────────────────────────────────────

    function insertHead() {
        const val = getInput('insertInput');
        if (val === '') { showMessage('Please enter a value to insert.', 'warning'); return; }
        ll.insertHead(val);
        showMessage(`✅ Inserted "${val}" at the head.`, 'success');
        render();
    }

    function insertTail() {
        const val = getInput('insertInput');
        if (val === '') { showMessage('Please enter a value to insert.', 'warning'); return; }
        ll.insertTail(val);
        showMessage(`✅ Inserted "${val}" at the tail.`, 'success');
        render();
    }

    function deleteNode() {
        const val = getInput('deleteInput');
        if (val === '') { showMessage('Please enter a value to delete.', 'warning'); return; }
        if (ll.size === 0) { showMessage('The list is already empty.', 'error'); return; }
        const deleted = ll.delete(val);
        if (deleted) {
            showMessage(`🗑 Deleted node with value "${val}".`, 'success');
            render();
        } else {
            showMessage(`❌ Value "${val}" not found in the list.`, 'error');
        }
    }

    function searchNode() {
        const val = getInput('searchInput');
        if (val === '') { showMessage('Please enter a value to search.', 'warning'); return; }
        if (ll.size === 0) { showMessage('The list is empty — nothing to search.', 'error'); return; }
        const idx = ll.search(val);
        if (idx !== -1) {
            showMessage(`🔍 Found "${val}" at index [${idx}]!`, 'success');
            render(idx);
            // Clear highlight after 2.5 seconds
            setTimeout(() => render(-1), 2500);
        } else {
            showMessage(`❌ Value "${val}" not found in the list.`, 'error');
            render();
        }
    }

    function clearList() {
        if (ll.size === 0) { showMessage('The list is already empty.', 'warning'); return; }
        ll.clear();
        showMessage('🧹 List cleared.', 'info');
        render();
    }

    // ─── Keyboard shortcuts ───────────────────────────────────────────────────

    document.getElementById('insertInput').addEventListener('keydown', e => {
        if (e.key === 'Enter') insertTail();
    });
    document.getElementById('deleteInput').addEventListener('keydown', e => {
        if (e.key === 'Enter') deleteNode();
    });
    document.getElementById('searchInput').addEventListener('keydown', e => {
        if (e.key === 'Enter') searchNode();
    });

    // ─── Init ─────────────────────────────────────────────────────────────────

    // Pre-populate with a few nodes for demo
    ['10', '20', '30', '40'].forEach(v => ll.insertTail(v));
    showMessage('👋 Demo list loaded — try inserting, deleting, or searching!', 'info');
    render();
</script>
</body>
</html>
```

## What's included

### Data Structure
- A proper `ListNode` + `SinglyLinkedList` class with `insertHead`, `insertTail`, `delete`, and `search` methods

### Visual Features
- **Color-coded nodes** — red border for Head, purple for Tail, gold when a node is both Head & Tail
- **Animated entry** — nodes pop in with a scale/fade animation
- **Search highlighting** — found node glows green with a pulsing animation, auto-clears after 2.5 seconds
- **NULL terminator** — dashed box at the end to show the list terminates
- **Empty state** — friendly icon + message when the list is empty

### Controls
| Control | Action |
|---|---|
| Value + Insert Head | Prepends to the list |
| Value + Insert Tail | Appends to the list |
| Delete field | Removes first matching node |
| Search field | Highlights the found node |
| Clear | Empties the entire list |
| `Enter` key | Works on all input fields |

### Stats Bar
Live-updating **Size**, **Head value**, and **Tail value** at the bottom

