<script>
  // ── Data Structure ──────────────────────────────────────────────────────────
  class Node {
    constructor(value) {
      this.value = value;
      this.next  = null;
    }
  }

  class LinkedList {
    constructor() {
      this.head   = null;
      this.length = 0;
    }

    insertHead(value) {
      const node = new Node(value);
      node.next  = this.head;
      this.head  = node;
      this.length++;
    }

    insertTail(value) {
      const node = new Node(value);
      if (!this.head) { this.head = node; this.length++; return; }
      let cur = this.head;
      while (cur.next) cur = cur.next;
      cur.next = node;
      this.length++;
    }

    delete(value) {
      if (!this.head) return false;
      if (this.head.value === value) {
        this.head = this.head.next;
        this.length--;
        return true;
      }
      let cur = this.head;
      while (cur.next) {
        if (cur.next.value === value) {
          cur.next = cur.next.next;
          this.length--;
          return true;
        }
        cur = cur.next;
      }
      return false;
    }

    search(value) {
      let cur = this.head, idx = 0;
      while (cur) {
        if (cur.value === value) return idx;
        cur = cur.next;
        idx++;
      }
      return -1;
    }

    toArray() {
      const arr = [];
      let cur = this.head;
      while (cur) { arr.push(cur.value); cur = cur.next; }
      return arr;
    }

    getTail() {
      if (!this.head) return null;
      let cur = this.head;
      while (cur.next) cur = cur.next;
      return cur.value;
    }

    clear() { this.head = null; this.length = 0; }
  }

  // ── State ───────────────────────────────────────────────────────────────────
  const list = new LinkedList();
  let   highlightedIndex = -1;
  let   msgTimer = null;

  // ── Message Helper ──────────────────────────────────────────────────────────
  function showMsg(text, type = 'info', duration = 3000) {
    const box = document.getElementById('msgBox');
    box.textContent = text;
    box.className   = `message-box ${type}`;
    if (msgTimer) clearTimeout(msgTimer);
    msgTimer = setTimeout(() => { box.className = 'message-box hidden'; }, duration);
  }

  // ── Render ──────────────────────────────────────────────────────────────────
  function render(highlightIdx = -1) {
    const container  = document.getElementById('listContainer');
    const emptyState = document.getElementById('emptyState');
    const arr        = list.toArray();

    // Stats
    document.getElementById('statLength').textContent = list.length;
    document.getElementById('statHead').textContent   = list.head ? list.head.value : 'null';
    document.getElementById('statTail').textContent   = list.getTail() !== null ? list.getTail() : 'null';

    if (arr.length === 0) {
      emptyState.style.display  = '';
      container.style.display   = 'none';
      container.innerHTML       = '';
      return;
    }

    emptyState.style.display = 'none';
    container.style.display  = 'flex';
    container.innerHTML      = '';

    arr.forEach((val, i) => {
      // Node wrapper
      const wrapper = document.createElement('div');
      wrapper.className = 'node-wrapper';

      // Node box
      const box = document.createElement('div');
      box.className = 'node-box';
      if (i === 0)            box.classList.add('head-node');
      if (i === highlightIdx) box.classList.add('highlighted');

      // Label
      const label = document.createElement('div');
      label.className = 'node-label';
      label.textContent = i === 0 ? 'HEAD' : (i === arr.length - 1 ? 'TAIL' : '');

      // Value
      const valEl = document.createElement('div');
      valEl.className   = 'node-value';
      valEl.textContent = val;

      // Index
      const idxEl = document.createElement('div');
      idxEl.className   = 'node-index';
      idxEl.textContent = `[${i}]`;

      box.appendChild(label);
      box.appendChild(valEl);
      box.appendChild(idxEl);
      wrapper.appendChild(box);

      // Arrow (not after last node)
      if (i < arr.length - 1) {
        const arrow = document.createElement('div');
        arrow.className = 'arrow';
        arrow.innerHTML = `
          <svg viewBox="0 0 40 24" fill="none" xmlns="http://www.w3.org/2000/svg">
            <line x1="2" y1="12" x2="32" y2="12" stroke="#e94560" stroke-width="2"/>
            <polyline points="26,6 34,12 26,18" stroke="#e94560" stroke-width="2"
                      fill="none" stroke-linecap="round" stroke-linejoin="round"/>
          </svg>`;
        wrapper.appendChild(arrow);
      }

      container.appendChild(wrapper);
    });

    // NULL terminal
    const arrowNull = document.createElement('div');
    arrowNull.className = 'arrow';
    arrowNull.innerHTML = `
      <svg viewBox="0 0 40 24" fill="none" xmlns="http://www.w3.org/2000/svg">
        <line x1="2" y1="12" x2="32" y2="12" stroke="#555" stroke-width="2" stroke-dasharray="4 3"/>
        <polyline points="26,6 34,12 26,18" stroke="#555" stroke-width="2"
                  fill="none" stroke-linecap="round" stroke-linejoin="round"/>
      </svg>`;

    const nullBox = document.createElement('div');
    nullBox.className   = 'null-node';
    nullBox.textContent = 'NULL';

    container.appendChild(arrowNull);
    container.appendChild(nullBox);
  }

  // ── Actions ─────────────────────────────────────────────────────────────────
  function getInt(id) {
    const v = document.getElementById(id).value.trim();
    if (v === '' || isNaN(v)) return null;
    return parseInt(v, 10);
  }

  function clearInput(id) {
    document.getElementById(id).value = '';
  }

  function insertAtHead() {
    const val = getInt('headVal');
    if (val === null) { showMsg('⚠ Please enter a valid integer.', 'warning'); return; }
    list.insertHead(val);
    clearInput('headVal');
    render();
    showMsg(`✔ Inserted ${val} at the head.`, 'success');
  }

  function insertAtTail() {
    const val = getInt('tailVal');
    if (val === null) { showMsg('⚠ Please enter a valid integer.', 'warning'); return; }
    list.insertTail(val);
    clearInput('tailVal');
    render();
    showMsg(`✔ Inserted ${val} at the tail.`, 'success');
  }

  function deleteNode() {
    const val = getInt('deleteVal');
    if (val === null) { showMsg('⚠ Please enter a valid integer.', 'warning'); return; }
    const deleted = list.delete(val);
    clearInput('deleteVal');
    if (deleted) {
      render();
      showMsg(`🗑 Deleted node with value ${val}.`, 'info');
    } else {
      showMsg(`✘ Value ${val} not found in the list.`, 'error');
    }
  }

  function searchNode() {
    const val = getInt('searchVal');
    if (val === null) { showMsg('⚠ Please enter a valid integer.', 'warning'); return; }
    const idx = list.search(val);
    clearInput('searchVal');
    if (idx !== -1) {
      render(idx);
      showMsg(`🔍 Found ${val} at index [${idx}].`, 'success');
      // Remove highlight after 3s
      setTimeout(() => render(), 3000);
    } else {
      render();
      showMsg(`✘ Value ${val} not found in the list.`, 'error');
    }
  }

  function clearList() {
    if (list.length === 0) { showMsg('ℹ The list is already empty.', 'info'); return; }
    list.clear();
    render();
    showMsg('🧹 List cleared.', 'info');
  }

  // Allow Enter key on inputs
  document.getElementById('headVal').addEventListener('keydown',   e => e.key === 'Enter' && insertAtHead());
  document.getElementById('tailVal').addEventListener('keydown',   e => e.key === 'Enter' && insertAtTail());
  document.getElementById('deleteVal').addEventListener('keydown', e => e.key === 'Enter' && deleteNode());
  document.getElementById('searchVal').addEventListener('keydown', e => e.key === 'Enter' && searchNode());

  // ── Seed with example data ──────────────────────────────────────────────────
  [10, 25, 37, 42, 58].forEach(v => list.insertTail(v));
  render();
</script>
</body>
</html>
```

