<body>

<h1>Singly Linked List</h1>
<p class="subtitle">Visualize & interact with a linked list in real time</p>

<!-- Controls -->
<div class="controls">

  <div class="control-group">
    <label>Insert at Head</label>
    <div class="input-row">
      <input type="text" id="headInput" placeholder="value" maxlength="6"/>
      <button class="btn-head" onclick="insertAtHead()">+ Head</button>
    </div>
  </div>

  <div class="control-group">
    <label>Insert at Tail</label>
    <div class="input-row">
      <input type="text" id="tailInput" placeholder="value" maxlength="6"/>
      <button class="btn-tail" onclick="insertAtTail()">+ Tail</button>
    </div>
  </div>

  <div class="control-group">
    <label>Delete by Value</label>
    <div class="input-row">
      <input type="text" id="deleteInput" placeholder="value" maxlength="6"/>
      <button class="btn-delete" onclick="deleteNode()">Delete</button>
    </div>
  </div>

  <div class="control-group">
    <label>Search Value</label>
    <div class="input-row">
      <input type="text" id="searchInput" placeholder="value" maxlength="6"/>
      <button class="btn-search" onclick="searchNode()">Search</button>
    </div>
  </div>

  <div class="control-group" style="flex:0; min-width:auto; justify-content:flex-end;">
    <label>Reset</label>
    <button class="btn-clear" onclick="clearList()">🗑 Clear All</button>
  </div>

</div>

<!-- Message -->
<div class="message" id="message"></div>

<!-- Visualization -->
<div class="canvas-wrapper">
  <div class="list-container" id="listContainer"></div>
</div>

<div class="stats" id="stats">Length: 0 nodes</div>

<script>
  // ── Data Structure ──────────────────────────────────────────────
  class ListNode {
    constructor(value) {
      this.value = value;
      this.next  = null;
      this.id    = Math.random().toString(36).slice(2, 8);
    }
  }

  class LinkedList {
    constructor() { this.head = null; this.size = 0; }

    insertAtHead(value) {
      const node = new ListNode(value);
      node.next  = this.head;
      this.head  = node;
      this.size++;
    }

    insertAtTail(value) {
      const node = new ListNode(value);
      if (!this.head) { this.head = node; this.size++; return; }
      let cur = this.head;
      while (cur.next) cur = cur.next;
      cur.next = node;
      this.size++;
    }

    delete(value) {
      if (!this.head) return false;
      if (String(this.head.value) === String(value)) {
        this.head = this.head.next;
        this.size--;
        return true;
      }
      let cur = this.head;
      while (cur.next) {
        if (String(cur.next.value) === String(value)) {
          cur.next = cur.next.next;
          this.size--;
          return true;
        }
        cur = cur.next;
      }
      return false;
    }

    search(value) {
      let cur = this.head, idx = 0;
      while (cur) {
        if (String(cur.value) === String(value)) return { node: cur, index: idx };
        cur = cur.next; idx++;
      }
      return null;
    }

    toArray() {
      const arr = []; let cur = this.head;
      while (cur) { arr.push(cur); cur = cur.next; }
      return arr;
    }

    clear() { this.head = null; this.size = 0; }
  }

  // ── State ───────────────────────────────────────────────────────
  const ll = new LinkedList();
  let highlightedId = null;
  let msgTimer      = null;

  // ── Message helper ──────────────────────────────────────────────
  function showMessage(text, type = 'info') {
    const el = document.getElementById('message');
    el.textContent = text;
    el.className   = `message show ${type}`;
    clearTimeout(msgTimer);
    msgTimer = setTimeout(() => el.classList.remove('show'), 3000);
  }

  // ── Render ──────────────────────────────────────────────────────
  function render() {
    const container = document.getElementById('listContainer');
    const nodes     = ll.toArray();

    container.innerHTML = '';

    if (nodes.length === 0) {
      container.innerHTML = `
        <div class="empty-state">
          <span class="empty-icon">🔗</span>
          <span>The list is empty. Insert a node to get started!</span>
        </div>`;
      document.getElementById('stats').textContent = 'Length: 0 nodes';
      return;
    }

    nodes.forEach((node, i) => {
      const wrapper = document.createElement('div');
      wrapper.className = 'node-wrapper';
      wrapper.id = `nw-${node.id}`;

      const isHead       = i === 0;
      const isHighlighted = node.id === highlightedId;
      const nextLabel    = node.next ? `→ ${node.next.value}` : 'null';

      wrapper.innerHTML = `
        <div class="node">
          <div class="node-box ${isHead ? 'head-node' : ''} ${isHighlighted ? 'highlighted' : ''}" id="nb-${node.id}">
            <div class="node-value">${escapeHtml(String(node.value))}</div>
            <div class="node-next">${escapeHtml(nextLabel)}</div>
          </div>
          <div class="node-label">${isHead ? 'HEAD' : `[${i}]`}</div>
        </div>`;

      container.appendChild(wrapper);

      // Arrow between nodes
      if (i < nodes.length - 1) {
        const arrow = document.createElement('div');
        arrow.className = 'arrow';
        arrow.innerHTML = `<div class="arrow-line"></div>`;
        container.appendChild(arrow);
      }
    });

    // NULL terminal
    const arrowToNull = document.createElement('div');
    arrowToNull.className = 'arrow';
    arrowToNull.innerHTML = `<div class="arrow-line"></div>`;
    container.appendChild(arrowToNull);

    const nullEl = document.createElement('div');
    nullEl.className = 'null-node';
    nullEl.innerHTML = `<div class="null-box">NULL</div>`;
    container.appendChild(nullEl);

    document.getElementById('stats').textContent =
      `Length: ${ll.size} node${ll.size !== 1 ? 's' : ''}`;
  }

  function escapeHtml(str) {
    return str.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
  }

  // ── Actions ─────────────────────────────────────────────────────
  function getInput(id) {
    const el  = document.getElementById(id);
    const val = el.value.trim();
    el.value  = '';
    return val;
  }

  function insertAtHead() {
    const val = getInput('headInput');
    if (val === '') { showMessage('Please enter a value.', 'warning'); return; }
    highlightedId = null;
    ll.insertAtHead(val);
    render();
    // Briefly highlight the new head
    highlightedId = ll.head.id;
    render();
    setTimeout(() => { highlightedId = null; render(); }, 1200);
    showMessage(`"${val}" inserted at head.`, 'info');
  }

  function insertAtTail() {
    const val = getInput('tailInput');
    if (val === '') { showMessage('Please enter a value.', 'warning'); return; }
    highlightedId = null;
    ll.insertAtTail(val);
    // Find tail id
    let cur = ll.head;
    while (cur.next) cur = cur.next;
    highlightedId = cur.id;
    render();
    setTimeout(() => { highlightedId = null; render(); }, 1200);
    showMessage(`"${val}" inserted at tail.`, 'info');
  }

  function deleteNode() {
    const val = getInput('deleteInput');
    if (val === '') { showMessage('Please enter a value to delete.', 'warning'); return; }
    highlightedId = null;
    const deleted = ll.delete(val);
    if (deleted) {
      render();
      showMessage(`Node with value "${val}" deleted.`, 'info');
    } else {
      showMessage(`Value "${val}" not found in the list.`, 'warning');
    }
  }

  function searchNode() {
    const val = getInput('searchInput');
    if (val === '') { showMessage('Please enter a value to search.', 'warning'); return; }
    const result = ll.search(val);
    if (result) {
      highlightedId = result.node.id;
      render();
      showMessage(`Found "${val}" at index ${result.index}.`, 'search');
      setTimeout(() => { highlightedId = null; render(); }, 2500);
    } else {
      highlightedId = null;
      render();
      showMessage(`Value "${val}" not found in the list.`, 'warning');
    }
  }

  function clearList() {
    ll.clear();
    highlightedId = null;
    render();
    showMessage('List cleared.', 'info');
  }

  // ── Keyboard shortcuts ──────────────────────────────────────────
  document.getElementById('headInput').addEventListener('keydown',   e => e.key === 'Enter' && insertAtHead());
  document.getElementById('tailInput').addEventListener('keydown',   e => e.key === 'Enter' && insertAtTail());
  document.getElementById('deleteInput').addEventListener('keydown', e => e.key === 'Enter' && deleteNode());
  document.getElementById('searchInput').addEventListener('keydown', e => e.key === 'Enter' && searchNode());

  // ── Seed with some initial nodes ────────────────────────────────
  ['10', '20', '30', '40'].forEach(v => ll.insertAtTail(v));
  render();
</script>
</body>
</html>
```

## Features

### Data Structure
- A proper `LinkedList` class with `ListNode` objects, each holding a `value`, `next` pointer, and a unique `id` for DOM tracking.

### Visualisation
| Element | Description |
|---|---|
| **Node box** | Two-section card — top shows the value, bottom shows the next pointer label |
| **Arrows** | Animated gradient lines with arrowheads between every node |
| **NULL terminal** | Dashed box at the end to represent the end of the list |
| **HEAD label** | Red-bordered node with a `HEAD` badge beneath it |

### Controls
- **Insert at Head** — prepends a node with a pop-in animation and brief highlight
- **Insert at Tail** — appends a node with the same animation
- **Delete by Value** — removes the first matching node and re-renders
- **Search** — highlights the found node in blue for 2.5 seconds
- **Clear All** — resets the entire list
- **Enter key** works on all inputs as a shortcut

### UX Details
- Empty state with a friendly message and icon
- Timed status messages (info / warning / search) with colour coding
- Hover lift effect on nodes
- Pre-seeded with `10 → 20 → 30 → 40` so it's immediately interactive

