<body>

<h1>Singly Linked List</h1>
<p class="subtitle">Interactive visualizer — insert, delete, and search nodes</p>

<!-- Controls -->
<div class="controls">

  <div class="control-group">
    <label>Value</label>
    <input id="inputHead" type="number" placeholder="e.g. 42" />
    <button class="btn-head" onclick="insertHead()">Insert Head</button>
  </div>

  <div class="control-group">
    <label>Value</label>
    <input id="inputTail" type="number" placeholder="e.g. 99" />
    <button class="btn-tail" onclick="insertTail()">Insert Tail</button>
  </div>

  <div class="control-group">
    <label>Value</label>
    <input id="inputDelete" type="number" placeholder="e.g. 7" />
    <button class="btn-delete" onclick="deleteNode()">Delete</button>
  </div>

  <div class="control-group">
    <label>Value</label>
    <input id="inputSearch" type="number" placeholder="e.g. 5" />
    <button class="btn-search" onclick="searchNode()">Search</button>
  </div>

  <div class="control-group">
    <button class="btn-clear" onclick="clearList()">Clear All</button>
  </div>

</div>

<!-- Message -->
<div class="message" id="message"></div>

<!-- Canvas -->
<div class="canvas-wrapper" id="canvas">
  <div class="empty-state" id="emptyState">
    <svg width="60" height="60" viewBox="0 0 60 60" fill="none">
      <rect x="5" y="18" width="22" height="24" rx="5" stroke="#64748b" stroke-width="2.5"/>
      <rect x="33" y="18" width="22" height="24" rx="5" stroke="#64748b" stroke-width="2.5" stroke-dasharray="5 3"/>
      <line x1="27" y1="30" x2="33" y2="30" stroke="#64748b" stroke-width="2.5"/>
      <polyline points="31,26 35,30 31,34" stroke="#64748b" stroke-width="2.5" fill="none" stroke-linejoin="round"/>
    </svg>
    <p>The list is empty. Insert a node to get started.</p>
  </div>
</div>

<div class="stats" id="stats"></div>

<script>
  // ── Data model ──────────────────────────────────────────────
  let head = null;
  let size = 0;

  class ListNode {
    constructor(val) {
      this.val = val;
      this.next = null;
    }
  }

  // ── Helpers ─────────────────────────────────────────────────
  function showMessage(text, type = 'info') {
    const el = document.getElementById('message');
    el.textContent = text;
    el.className = `message ${type} show`;
    clearTimeout(el._timer);
    el._timer = setTimeout(() => el.classList.remove('show'), 3000);
  }

  function getInput(id) {
    const el = document.getElementById(id);
    const val = el.value.trim();
    el.value = '';
    if (val === '' || isNaN(val)) return null;
    return parseInt(val, 10);
  }

  function updateStats() {
    const el = document.getElementById('stats');
    if (size === 0) { el.textContent = ''; return; }
    // collect values
    let vals = [], cur = head;
    while (cur) { vals.push(cur.val); cur = cur.next; }
    el.innerHTML = `Nodes: <span>${size}</span> &nbsp;|&nbsp; Head: <span>${head.val}</span> &nbsp;|&nbsp; Values: <span>${vals.join(' → ')}</span>`;
  }

  // ── Operations ──────────────────────────────────────────────
  function insertHead() {
    const val = getInput('inputHead');
    if (val === null) { showMessage('Please enter a valid integer.', 'error'); return; }
    const node = new ListNode(val);
    node.next = head;
    head = node;
    size++;
    showMessage(`Inserted ${val} at head.`, 'success');
    render();
  }

  function insertTail() {
    const val = getInput('inputTail');
    if (val === null) { showMessage('Please enter a valid integer.', 'error'); return; }
    const node = new ListNode(val);
    if (!head) { head = node; }
    else {
      let cur = head;
      while (cur.next) cur = cur.next;
      cur.next = node;
    }
    size++;
    showMessage(`Inserted ${val} at tail.`, 'success');
    render();
  }

  function deleteNode() {
    const val = getInput('inputDelete');
    if (val === null) { showMessage('Please enter a valid integer.', 'error'); return; }
    if (!head) { showMessage('List is empty.', 'error'); return; }

    if (head.val === val) {
      animateDelete(0, () => {
        head = head.next;
        size--;
        showMessage(`Deleted node with value ${val}.`, 'success');
        render();
      });
      return;
    }

    let cur = head, idx = 1;
    while (cur.next) {
      if (cur.next.val === val) {
        animateDelete(idx, () => {
          cur.next = cur.next.next;
          size--;
          showMessage(`Deleted node with value ${val}.`, 'success');
          render();
        });
        return;
      }
      cur = cur.next;
      idx++;
    }
    showMessage(`Value ${val} not found in list.`, 'error');
  }

  function searchNode() {
    const val = getInput('inputSearch');
    if (val === null) { showMessage('Please enter a valid integer.', 'error'); return; }
    if (!head) { showMessage('List is empty.', 'error'); return; }

    let cur = head, idx = 0;
    while (cur) {
      if (cur.val === val) {
        render(idx);
        showMessage(`Found ${val} at position ${idx}.`, 'info');
        return;
      }
      cur = cur.next;
      idx++;
    }
    showMessage(`Value ${val} not found in list.`, 'error');
    render(); // clear any previous highlight
  }

  function clearList() {
    head = null;
    size = 0;
    showMessage('List cleared.', 'info');
    render();
  }

  // ── Animation helper ────────────────────────────────────────
  function animateDelete(index, callback) {
    const nodes = document.querySelectorAll('.node');
    if (nodes[index]) {
      nodes[index].classList.add('deleting');
      setTimeout(callback, 320);
    } else {
      callback();
    }
  }

  // ── Render ──────────────────────────────────────────────────
  function render(highlightIdx = -1) {
    const canvas = document.getElementById('canvas');
    const empty  = document.getElementById('emptyState');

    if (!head) {
      canvas.innerHTML = '';
      canvas.appendChild(empty);
      empty.style.display = 'flex';
      updateStats();
      return;
    }

    // Build list row
    const row = document.createElement('div');
    row.className = 'list-row';

    // HEAD label
    const headLabel = document.createElement('div');
    headLabel.className = 'head-label';
    headLabel.textContent = 'HEAD';
    row.appendChild(headLabel);

    let cur = head, idx = 0;
    while (cur) {
      // Node box
      const nodeEl = document.createElement('div');
      nodeEl.className = 'node' + (idx === highlightIdx ? ' found' : '');

      const dataEl = document.createElement('div');
      dataEl.className = 'node-data';
      dataEl.textContent = cur.val;

      const nextEl = document.createElement('div');
      nextEl.className = 'node-next';
      nextEl.textContent = cur.next ? 'next →' : 'next: NULL';

      nodeEl.appendChild(dataEl);
      nodeEl.appendChild(nextEl);
      row.appendChild(nodeEl);

      // Arrow to next (or NULL)
      if (cur.next) {
        row.appendChild(makeArrow('#38bdf8'));
      } else {
        row.appendChild(makeArrow('#475569'));
        // NULL pill
        const nullPill = document.createElement('div');
        nullPill.className = 'null-pill';
        nullPill.textContent = 'NULL';
        row.appendChild(nullPill);
      }

      cur = cur.next;
      idx++;
    }

    canvas.innerHTML = '';
    canvas.appendChild(row);
    updateStats();
  }

  function makeArrow(color) {
    const wrap = document.createElement('div');
    wrap.className = 'arrow';
    wrap.innerHTML = `
      <svg viewBox="0 0 48 24" fill="none" xmlns="http://www.w3.org/2000/svg">
        <line x1="0" y1="12" x2="40" y2="12" stroke="${color}" stroke-width="2.5" stroke-linecap="round"/>
        <polyline points="34,6 42,12 34,18" stroke="${color}" stroke-width="2.5"
                  fill="none" stroke-linejoin="round" stroke-linecap="round"/>
      </svg>`;
    return wrap;
  }

  // ── Keyboard shortcuts ───────────────────────────────────────
  ['inputHead','inputTail','inputDelete','inputSearch'].forEach((id, i) => {
    document.getElementById(id).addEventListener('keydown', e => {
      if (e.key === 'Enter') {
        [insertHead, insertTail, deleteNode, searchNode][i]();
      }
    });
  });

  // ── Init ─────────────────────────────────────────────────────
  // Seed with a small example
  [10, 25, 37, 52].forEach(v => {
    const n = new ListNode(v);
    if (!head) { head = n; }
    else {
      let c = head; while (c.next) c = c.next; c.next = n;
    }
    size++;
  });
  render();
</script>
</body>
</html>
```

## Features

### Visual Design
- **Dark theme** with a blue/indigo gradient palette
- Each node is rendered as a **two-part box** — a data cell on top and a `next` label below
- **Animated arrows** (SVG) connect nodes, pointing right toward the next node or a `NULL` pill at the tail
- **Pop-in animation** when a node is inserted, **pop-out animation** before deletion

### Controls
| Action | Behavior |
|---|---|
| **Insert Head** | Prepends a new node; arrow chain updates immediately |
| **Insert Tail** | Appends to the end; NULL pill shifts right |
| **Delete** | Animates the target node shrinking out, then re-renders |
| **Search** | Highlights the found node in amber with a glow and lift effect |
| **Clear All** | Resets to the empty state |

### Edge Cases Handled
- **Empty list** — shows a friendly illustrated empty state
- **Invalid / blank input** — shows a red error message
- **Value not found** — shows an error without crashing
- **Keyboard** — press `Enter` in any input field to trigger its action
- **Stats bar** — shows node count, head value, and full value sequence

