      color: #334155;
    }

    /* ── Info bar ── */
    .info-bar {
      margin-top: 20px;
      font-size: 0.8rem;
      color: #475569;
      display: flex;
      gap: 20px;
      flex-wrap: wrap;
      justify-content: center;
    }

    .info-bar span { color: #64748b; }
    .info-bar strong { color: #94a3b8; }
  </style>
</head>
<body>

  <h1>Singly Linked List</h1>
  <p class="subtitle">Visualize, insert, delete, and search nodes interactively</p>

  <!-- Controls -->
  <div class="controls">

    <div class="control-group">
      <label>Value</label>
      <input type="number" id="headVal" placeholder="e.g. 42" />
      <button class="btn-head" onclick="insertHead()">Insert Head</button>
    </div>

    <div class="control-group">
      <label>Value</label>
      <input type="number" id="tailVal" placeholder="e.g. 99" />
      <button class="btn-tail" onclick="insertTail()">Insert Tail</button>
    </div>

    <div class="control-group">
      <label>Value</label>
      <input type="number" id="delVal" placeholder="e.g. 7" />
      <button class="btn-delete" onclick="deleteNode()">Delete</button>
    </div>

    <div class="control-group">
      <label>Value</label>
      <input type="number" id="searchVal" placeholder="e.g. 55" />
      <button class="btn-search" onclick="searchNode()">Search</button>
    </div>

    <div class="control-group">
      <button class="btn-clear" onclick="clearList()">Clear List</button>
    </div>

  </div>

  <!-- Message -->
  <div class="message hidden" id="message"></div>

  <!-- Canvas -->
  <div class="canvas-wrapper" id="canvas">
    <div class="empty-state" id="emptyState">
      <div class="empty-icon">🔗</div>
      <div class="empty-text">The list is empty</div>
      <div class="empty-hint">Use the controls above to insert nodes</div>
    </div>
    <div class="list-row" id="listRow" style="display:none;"></div>
  </div>

  <!-- Info bar -->
  <div class="info-bar">
    <div>Length: <strong id="lengthDisplay">0</strong></div>
    <div>Head: <strong id="headDisplay">null</strong></div>
    <div>Tail: <strong id="tailDisplay">null</strong></div>
  </div>

<script>
  /* ────────────────────────────────────────────
     Data Model
  ──────────────────────────────────────────── */
  class ListNode {
    constructor(val) {
      this.val = val;
      this.next = null;
    }
  }

  class LinkedList {
    constructor() { this.head = null; this.size = 0; }

    insertHead(val) {
      const node = new ListNode(val);
      node.next = this.head;
      this.head = node;
      this.size++;
    }

    insertTail(val) {
      const node = new ListNode(val);
      if (!this.head) { this.head = node; this.size++; return; }
      let cur = this.head;
      while (cur.next) cur = cur.next;
      cur.next = node;
      this.size++;
    }

    // Returns true if deleted, false if not found
    delete(val) {
      if (!this.head) return false;
      if (this.head.val === val) {
        this.head = this.head.next;
        this.size--;
        return true;
      }
      let cur = this.head;
      while (cur.next) {
        if (cur.next.val === val) {
          cur.next = cur.next.next;
          this.size--;
          return true;
        }
        cur = cur.next;
      }
      return false;
    }

    // Returns 0-based index or -1
    search(val) {
      let cur = this.head, idx = 0;
      while (cur) {
        if (cur.val === val) return idx;
        cur = cur.next;
        idx++;
      }
      return -1;
    }

    toArray() {
      const arr = [];
      let cur = this.head;
      while (cur) { arr.push(cur.val); cur = cur.next; }
      return arr;
    }

    get tail() {
      if (!this.head) return null;
      let cur = this.head;
      while (cur.next) cur = cur.next;
      return cur.val;
    }
  }

  /* ────────────────────────────────────────────
     State
  ──────────────────────────────────────────── */
  const ll = new LinkedList();
  let highlightedIndex = -1;
  let msgTimer = null;

  /* ────────────────────────────────────────────
     Render
  ──────────────────────────────────────────── */
  function render(highlightIdx = -1) {
    const arr = ll.toArray();
    const listRow    = document.getElementById('listRow');
    const emptyState = document.getElementById('emptyState');

    // Update info bar
    document.getElementById('lengthDisplay').textContent = ll.size;
    document.getElementById('headDisplay').textContent   = ll.head ? ll.head.val : 'null';
    document.getElementById('tailDisplay').textContent   = ll.tail !== null ? ll.tail : 'null';

    if (arr.length === 0) {
      emptyState.style.display = 'flex';
      listRow.style.display = 'none';
      listRow.innerHTML = '';
      return;
    }

    emptyState.style.display = 'none';
    listRow.style.display = 'flex';
    listRow.innerHTML = '';

    arr.forEach((val, i) => {
      // Node wrapper
      const nodeEl = document.createElement('div');
      nodeEl.className = 'node';

      // Label (HEAD / index)
      const label = document.createElement('div');
      label.className = 'node-label';
      label.textContent = i === 0 ? 'HEAD' : `[${i}]`;
      nodeEl.appendChild(label);

      // Box
      const box = document.createElement('div');
      box.className = 'node-box' + (i === highlightIdx ? ' highlighted' : '');

      const valDiv = document.createElement('div');
      valDiv.className = 'node-value';
      valDiv.textContent = val;

      const nextDiv = document.createElement('div');
      nextDiv.className = 'node-next';
      nextDiv.textContent = 'next';

      box.appendChild(valDiv);
      box.appendChild(nextDiv);
      nodeEl.appendChild(box);
      listRow.appendChild(nodeEl);

      // Arrow (between nodes)
      if (i < arr.length - 1) {
        const arrowContainer = document.createElement('div');
        arrowContainer.className = 'arrow-container';
        const arrow = document.createElement('div');
        arrow.className = 'arrow';
        const line = document.createElement('div');
        line.className = 'arrow-line';
        const head = document.createElement('div');
        head.className = 'arrow-head';
        arrow.appendChild(line);
        arrow.appendChild(head);
        arrowContainer.appendChild(arrow);
        listRow.appendChild(arrowContainer);
      }
    });

    // Arrow to NULL
    const arrowContainer = document.createElement('div');
    arrowContainer.className = 'arrow-container';
    const arrow = document.createElement('div');
    arrow.className = 'arrow';
    const line = document.createElement('div');
    line.className = 'arrow-line';
    const head = document.createElement('div');
    head.className = 'arrow-head';
    arrow.appendChild(line);
    arrow.appendChild(head);
    arrowContainer.appendChild(arrow);
    listRow.appendChild(arrowContainer);

    // NULL node
    const nullEl = document.createElement('div');
    nullEl.className = 'null-node';
    const nullBox = document.createElement('div');
    nullBox.className = 'null-box';
    nullBox.textContent = 'NULL';
    nullEl.appendChild(nullBox);
    listRow.appendChild(nullEl);
  }

  /* ────────────────────────────────────────────
     Message helper
  ──────────────────────────────────────────── */
  function showMessage(text, type = 'info', duration = 3000) {
    const el = document.getElementById('message');
    el.textContent = text;
    el.className = `message ${type}`;
    if (msgTimer) clearTimeout(msgTimer);
    msgTimer = setTimeout(() => { el.className = 'message hidden'; }, duration);
  }

  /* ────────────────────────────────────────────
     Actions
  ──────────────────────────────────────────── */
  function getVal(id) {
    const el = document.getElementById(id);
    const v = el.value.trim();
    el.value = '';
    if (v === '') return null;
    return parseInt(v, 10);
  }

  function insertHead() {
    const val = getVal('headVal');
    if (val === null) { showMessage('Please enter a value.', 'error'); return; }
    ll.insertHead(val);
    render();
    showMessage(`Inserted ${val} at head.`, 'success');
  }

  function insertTail() {
    const val = getVal('tailVal');
    if (val === null) { showMessage('Please enter a value.', 'error'); return; }
    ll.insertTail(val);
    render();
    showMessage(`Inserted ${val} at tail.`, 'success');
  }

  function deleteNode() {
    const val = getVal('delVal');
    if (val === null) { showMessage('Please enter a value.', 'error'); return; }
    if (ll.size === 0) { showMessage('List is already empty.', 'error'); return; }
    const ok = ll.delete(val);
    render();
    if (ok) showMessage(`Deleted node with value ${val}.`, 'success');
    else    showMessage(`Value ${val} not found in the list.`, 'error');
  }

  function searchNode() {
    const val = getVal('searchVal');
    if (val === null) { showMessage('Please enter a value.', 'error'); return; }
    if (ll.size === 0) { showMessage('List is empty — nothing to search.', 'error'); return; }
    const idx = ll.search(val);
    if (idx === -1) {
      render();
      showMessage(`Value ${val} not found in the list.`, 'error');
    } else {
      render(idx);
      showMessage(`Found ${val} at index ${idx}! ✓`, 'success', 4000);
      // Auto-clear highlight after 4s
      setTimeout(() => render(), 4200);
    }
  }

  function clearList() {
    ll.head = null;
    ll.size = 0;
    render();
    showMessage('List cleared.', 'info');
  }

  /* ────────────────────────────────────────────
     Keyboard shortcuts (Enter key on inputs)
  ──────────────────────────────────────────── */
  document.getElementById('headVal').addEventListener('keydown',   e => e.key === 'Enter' && insertHead());
  document.getElementById('tailVal').addEventListener('keydown',   e => e.key === 'Enter' && insertTail());
  document.getElementById('delVal').addEventListener('keydown',    e => e.key === 'Enter' && deleteNode());
  document.getElementById('searchVal').addEventListener('keydown', e => e.key === 'Enter' && searchNode());

  /* ────────────────────────────────────────────
     Init with a sample list
  ──────────────────────────────────────────── */
  [10, 25, 37, 52, 68].forEach(v => ll.insertTail(v));
  render();
</script>
</body>
</html>
```

## Features

### Visual Design
- **Dark theme** with a clean, modern aesthetic
- Each node is rendered as a **two-part box** — a value cell and a `next` pointer cell — connected by **gradient arrows**
- Nodes **animate in** with a spring pop effect on insertion
- The **NULL terminator** is always shown at the end of the list

### Controls
| Control | Description |
|---|---|
| **Insert Head** | Prepends a new node, O(1) |
| **Insert Tail** | Appends a new node, O(n) |
| **Delete** | Removes first occurrence of a value |
| **Search** | Highlights the found node with a pulsing green glow |
| **Clear** | Resets the entire list |

### Extra Details
- **Enter key** works on all inputs
- **Info bar** tracks live list length, head value, and tail value
- **Empty state** shows a friendly placeholder with an icon
- Color-coded **status messages** (success / error / info) auto-dismiss
- Preloaded with `10 → 25 → 37 → 52 → 68` so you can explore immediately
- Horizontally scrollable canvas for long lists

