<body>

<h1>Linked List Visualizer</h1>
<p class="subtitle">Singly linked list — insert, delete, search</p>

<div class="controls">
  <div class="control-group">
    <input type="text" id="inputVal" placeholder="value" maxlength="6" />
  </div>
  <div class="control-group">
    <button class="btn-head" onclick="insertHead()">Insert Head</button>
    <button class="btn-tail" onclick="insertTail()">Insert Tail</button>
  </div>
  <div class="control-group">
    <button class="btn-delete" onclick="deleteVal()">Delete</button>
    <button class="btn-search" onclick="searchVal()">Search</button>
  </div>
  <div class="control-group">
    <button class="btn-clear" onclick="clearList()">Clear List</button>
  </div>
</div>

<div class="message" id="message">Use the controls above to build your linked list.</div>

<div class="canvas-wrapper">
  <div class="list-container" id="listContainer"></div>
</div>

<div class="stats">
  Length: <span id="statLength">0</span> &nbsp;|&nbsp;
  Head: <span id="statHead">null</span> &nbsp;|&nbsp;
  Tail: <span id="statTail">null</span>
</div>

<script>
  // ── Data model ──────────────────────────────────────────────
  class ListNode {
    constructor(val) {
      this.val = val;
      this.next = null;
      this.id = Math.random().toString(36).slice(2, 8);
    }
  }

  let head = null;
  let size = 0;
  let highlightIds = {};   // id -> class string

  // ── Helpers ──────────────────────────────────────────────────
  function getInput() {
    const v = document.getElementById('inputVal').value.trim();
    return v;
  }

  function setMessage(text, type = '') {
    const el = document.getElementById('message');
    el.textContent = text;
    el.className = 'message ' + type;
  }

  function getTail() {
    if (!head) return null;
    let cur = head;
    while (cur.next) cur = cur.next;
    return cur;
  }

  // ── Operations ───────────────────────────────────────────────
  function insertHead() {
    const val = getInput();
    if (!val) { setMessage('Please enter a value.', 'error'); return; }

    const node = new ListNode(val);
    node.next = head;
    head = node;
    size++;

    highlightIds = { [node.id]: 'highlight-head' };
    setMessage(`Inserted "${val}" at head.`, 'success');
    render();
    setTimeout(() => { highlightIds = {}; render(); }, 1400);
  }

  function insertTail() {
    const val = getInput();
    if (!val) { setMessage('Please enter a value.', 'error'); return; }

    const node = new ListNode(val);
    if (!head) {
      head = node;
    } else {
      getTail().next = node;
    }
    size++;

    highlightIds = { [node.id]: 'highlight-tail' };
    setMessage(`Inserted "${val}" at tail.`, 'success');
    render();
    setTimeout(() => { highlightIds = {}; render(); }, 1400);
  }

  function deleteVal() {
    const val = getInput();
    if (!val) { setMessage('Please enter a value to delete.', 'error'); return; }
    if (!head) { setMessage('List is empty.', 'error'); return; }

    // Find the node element first so we can animate
    let cur = head, prev = null, found = null;
    while (cur) {
      if (String(cur.val) === String(val)) { found = cur; break; }
      prev = cur;
      cur = cur.next;
    }

    if (!found) {
      setMessage(`Value "${val}" not found in list.`, 'error');
      return;
    }

    // Animate then remove
    highlightIds = { [found.id]: 'highlight-found' };
    render();

    setTimeout(() => {
      // Actually remove
      if (!prev) {
        head = found.next;
      } else {
        prev.next = found.next;
      }
      size--;
      highlightIds = {};
      setMessage(`Deleted "${val}" from list.`, 'success');
      render();
    }, 500);
  }

  function searchVal() {
    const val = getInput();
    if (!val) { setMessage('Please enter a value to search.', 'error'); return; }
    if (!head) { setMessage('List is empty.', 'error'); return; }

    let cur = head, idx = 0;
    while (cur) {
      if (String(cur.val) === String(val)) {
        highlightIds = { [cur.id]: 'highlight-found' };
        setMessage(`Found "${val}" at index ${idx}.`, 'info');
        render();
        setTimeout(() => { highlightIds = {}; render(); }, 2000);
        return;
      }
      cur = cur.next;
      idx++;
    }
    setMessage(`Value "${val}" not found in list.`, 'error');
  }

  function clearList() {
    head = null;
    size = 0;
    highlightIds = {};
    setMessage('List cleared.', 'info');
    render();
  }

  // ── Render ───────────────────────────────────────────────────
  function render() {
    const container = document.getElementById('listContainer');
    container.innerHTML = '';

    // Update stats
    document.getElementById('statLength').textContent = size;
    document.getElementById('statHead').textContent = head ? head.val : 'null';
    const t = getTail();
    document.getElementById('statTail').textContent = t ? t.val : 'null';

    if (!head) {
      container.innerHTML = `
        <div class="empty-state">
          <svg width="48" height="48" viewBox="0 0 24 24" fill="none" stroke="#7eb8f7" stroke-width="1.5">
            <rect x="3" y="8" width="5" height="8" rx="1"/>
            <rect x="10" y="8" width="5" height="8" rx="1"/>
            <rect x="17" y="8" width="4" height="8" rx="1" stroke-dasharray="2 1"/>
          </svg>
          <p>Empty list — insert a node to get started</p>
        </div>`;
      return;
    }

    const tail = getTail();
    let cur = head;

    while (cur) {
      const isHead = cur === head;
      const isTail = cur === tail;
      const hlClass = highlightIds[cur.id] || '';

      // Label
      let labelHTML = '';
      if (isHead && isTail) {
        labelHTML = `<div class="node-label label-both">HEAD / TAIL</div>`;
      } else if (isHead) {
        labelHTML = `<div class="node-label label-head">HEAD</div>`;
      } else if (isTail) {
        labelHTML = `<div class="node-label label-tail">TAIL</div>`;
      }

      const nextText = cur.next ? 'next →' : 'null';

      const wrapper = document.createElement('div');
      wrapper.className = 'node-wrapper';
      wrapper.innerHTML = `
        <div class="node ${hlClass}" id="node-${cur.id}">
          ${labelHTML}
          <div class="node-data">${escapeHTML(String(cur.val))}</div>
          <div class="node-next">${nextText}</div>
        </div>`;

      container.appendChild(wrapper);

      if (cur.next) {
        const arrow = document.createElement('div');
        arrow.className = 'arrow-connector';
        arrow.innerHTML = `<div class="arrow-line"></div>`;
        container.appendChild(arrow);
      }

      cur = cur.next;
    }

    // NULL terminator
    const nullArrow = document.createElement('div');
    nullArrow.className = 'arrow-connector';
    nullArrow.innerHTML = `<div class="arrow-line"></div>`;
    container.appendChild(nullArrow);

    const nullNode = document.createElement('div');
    nullNode.className = 'null-node';
    nullNode.innerHTML = `<div class="null-box">NULL</div>`;
    container.appendChild(nullNode);
  }

  function escapeHTML(str) {
    return str.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
  }

  // Allow Enter key
  document.getElementById('inputVal').addEventListener('keydown', e => {
    if (e.key === 'Enter') insertTail();
  });

  // Initial render
  render();
</script>
</body>
</html>
```

Here's what makes this one actually work correctly:

**Arrows**
- Pure CSS arrows — a `div` with a fixed width and an `::after` pseudo-element forming a proper arrowhead. No SVG coordinate math that breaks on resize, no `getBoundingClientRect` timing issues.

**Node structure**
- Each node renders two cells side by side: **data** | **next**, mirroring how a linked list node actually looks in memory. The `next` cell shows `next →` or `null` depending on whether a successor exists.

**NULL terminator**
- The list always ends with an arrow pointing to a dashed `NULL` box — including the single-node case.

**Empty state**
- Detected before any rendering attempt, shows a clear placeholder instead of a broken partial render.

**HEAD / TAIL labels**
- Positioned absolutely above each node. When the list has one element, it shows `HEAD / TAIL` combined.

**Controls**
- Insert at head, insert at tail, delete by value (with 500ms highlight before removal), search with 2s yellow highlight, and clear. Enter key triggers insert at tail.

