<h1>Linked List Visualizer</h1>
<p class="subtitle">Insert · Delete · Search — all with live arrows</p>

<div class="controls">
  <div class="control-group">
    <label>Value</label>
    <input type="text" id="inputVal" placeholder="e.g. 42" maxlength="6">
    <button class="btn-head" onclick="insertHead()">Insert Head</button>
    <button class="btn-tail" onclick="insertTail()">Insert Tail</button>
  </div>
  <div class="control-group">
    <label>Delete</label>
    <input type="text" id="deleteVal" placeholder="value" maxlength="6">
    <button class="btn-delete" onclick="deleteNode()">Delete</button>
  </div>
  <div class="control-group">
    <label>Search</label>
    <input type="text" id="searchVal" placeholder="value" maxlength="6">
    <button class="btn-search" onclick="searchNode()">Search</button>
  </div>
  <div class="control-group">
    <button class="btn-clear" onclick="clearList()">Clear All</button>
  </div>
</div>

<div class="message" id="message"></div>

<div class="viz-wrapper" id="vizWrapper">
  <div class="empty-msg" id="emptyMsg">List is empty — insert a node to begin</div>
  <div class="list-container" id="listContainer"></div>
</div>

<div class="info-bar">
  Length: <span id="lengthDisplay">0</span> &nbsp;|&nbsp;
  Head: <span id="headDisplay">null</span> &nbsp;|&nbsp;
  Tail: <span id="tailDisplay">null</span>
</div>

<script>
  // ── Data model ──────────────────────────────────────────────
  class ListNode {
    constructor(val) {
      this.val = val;
      this.next = null;
      this.id = Math.random().toString(36).slice(2, 8);
    }
  }

  let head = null;
  let size = 0;
  let highlightIds = {};   // id -> 'found' | 'not-found'
  let msgTimer = null;

  // ── Message helper ──────────────────────────────────────────
  function showMsg(text, color = '#fbbf24') {
    const el = document.getElementById('message');
    el.textContent = text;
    el.style.color = color;
    if (msgTimer) clearTimeout(msgTimer);
    msgTimer = setTimeout(() => { el.textContent = ''; }, 3000);
  }

  // ── List operations ─────────────────────────────────────────
  function insertHead() {
    const val = document.getElementById('inputVal').value.trim();
    if (!val) { showMsg('Please enter a value.', '#f87171'); return; }
    highlightIds = {};
    const node = new ListNode(val);
    node.next = head;
    head = node;
    size++;
    render();
    showMsg(`Inserted "${val}" at head.`, '#7dd3fc');
    document.getElementById('inputVal').value = '';
  }

  function insertTail() {
    const val = document.getElementById('inputVal').value.trim();
    if (!val) { showMsg('Please enter a value.', '#f87171'); return; }
    highlightIds = {};
    const node = new ListNode(val);
    if (!head) {
      head = node;
    } else {
      let cur = head;
      while (cur.next) cur = cur.next;
      cur.next = node;
    }
    size++;
    render();
    showMsg(`Inserted "${val}" at tail.`, '#c4b5fd');
    document.getElementById('inputVal').value = '';
  }

  function deleteNode() {
    const val = document.getElementById('deleteVal').value.trim();
    if (!val) { showMsg('Please enter a value to delete.', '#f87171'); return; }
    highlightIds = {};

    if (!head) { showMsg('List is empty.', '#f87171'); return; }

    if (head.val === val) {
      head = head.next;
      size--;
      render();
      showMsg(`Deleted "${val}".`, '#f87171');
      document.getElementById('deleteVal').value = '';
      return;
    }

    let cur = head;
    while (cur.next && cur.next.val !== val) cur = cur.next;

    if (!cur.next) {
      showMsg(`Value "${val}" not found.`, '#f87171');
      return;
    }

    cur.next = cur.next.next;
    size--;
    render();
    showMsg(`Deleted "${val}".`, '#f87171');
    document.getElementById('deleteVal').value = '';
  }

  function searchNode() {
    const val = document.getElementById('searchVal').value.trim();
    if (!val) { showMsg('Please enter a value to search.', '#f87171'); return; }
    highlightIds = {};

    let cur = head;
    let found = false;
    while (cur) {
      if (cur.val === val) {
        highlightIds[cur.id] = 'found';
        found = true;
      }
      cur = cur.next;
    }

    if (!found && head) {
      // mark all as not-found briefly
      cur = head;
      while (cur) { highlightIds[cur.id] = 'not-found'; cur = cur.next; }
    }

    render();

    if (found) {
      showMsg(`Found "${val}" in the list! ✓`, '#34d399');
    } else if (!head) {
      showMsg('List is empty.', '#f87171');
    } else {
      showMsg(`"${val}" not found in the list.`, '#f87171');
    }

    // clear highlights after 2s
    setTimeout(() => { highlightIds = {}; render(); }, 2000);
  }

  function clearList() {
    head = null;
    size = 0;
    highlightIds = {};
    render();
    showMsg('List cleared.', '#94a3b8');
  }

  // ── Render ──────────────────────────────────────────────────
  function render() {
    const container  = document.getElementById('listContainer');
    const emptyMsg   = document.getElementById('emptyMsg');
    const lengthDisp = document.getElementById('lengthDisplay');
    const headDisp   = document.getElementById('headDisplay');
    const tailDisp   = document.getElementById('tailDisplay');

    container.innerHTML = '';

    if (!head) {
      emptyMsg.style.display = 'block';
      lengthDisp.textContent = '0';
      headDisp.textContent   = 'null';
      tailDisp.textContent   = 'null';
      return;
    }

    emptyMsg.style.display = 'none';

    // Collect nodes into array for easy tail detection
    const nodes = [];
    let cur = head;
    while (cur) { nodes.push(cur); cur = cur.next; }

    lengthDisp.textContent = nodes.length;
    headDisp.textContent   = nodes[0].val;
    tailDisp.textContent   = nodes[nodes.length - 1].val;

    nodes.forEach((node, i) => {
      const isHead = i === 0;
      const isTail = i === nodes.length - 1;
      const hlClass = highlightIds[node.id]
        ? (highlightIds[node.id] === 'found' ? 'highlight-found' : 'highlight-not-found')
        : '';

      // Wrapper with labels above
      const wrapper = document.createElement('div');
      wrapper.className = 'node-wrapper';

      // node-with-labels column
      const nwl = document.createElement('div');
      nwl.className = 'node-with-labels';

      // Tags row
      const tags = document.createElement('div');
      tags.className = 'node-tags';
      if (isHead) {
        const hl = document.createElement('span');
        hl.className = 'head-label';
        hl.textContent = 'head';
        tags.appendChild(hl);
      }
      if (isTail) {
        const tl = document.createElement('span');
        tl.className = 'tail-label';
        tl.textContent = 'tail';
        tags.appendChild(tl);
      }
      nwl.appendChild(tags);

      // Node box
      const nodeEl = document.createElement('div');
      nodeEl.className = 'node' + (hlClass ? ' ' + hlClass : '');
      nodeEl.innerHTML = `
        <div class="node-data">
          <span class="node-label">data</span>
          <span class="node-value" title="${node.val}">${node.val}</span>
        </div>
        <div class="node-pointer">
          <span class="ptr-label">next</span>
          <div class="ptr-dot ${isTail ? 'null-dot' : ''}"></div>
        </div>
      `;
      nwl.appendChild(nodeEl);
      wrapper.appendChild(nwl);

      // Arrow to next node (not after last)
      if (!isTail) {
        const arrow = document.createElement('div');
        arrow.className = 'arrow-segment';
        arrow.innerHTML = `<div class="arrow-line"></div><div class="arrow-head"></div>`;
        wrapper.appendChild(arrow);
      }

      container.appendChild(wrapper);
    });

    // NULL terminator after last node
    const nullSeg = document.createElement('div');
    nullSeg.className = 'null-segment';
    nullSeg.innerHTML = `
      <div class="null-arrow-line"></div>
      <div class="null-arrow-head"></div>
      <div class="null-box">NULL</div>
    `;
    container.appendChild(nullSeg);
  }

  // ── Keyboard shortcut: Enter submits insert ─────────────────
  document.getElementById('inputVal').addEventListener('keydown', e => {
    if (e.key === 'Enter') insertTail();
  });
  document.getElementById('deleteVal').addEventListener('keydown', e => {
    if (e.key === 'Enter') deleteNode();
  });
  document.getElementById('searchVal').addEventListener('keydown', e => {
    if (e.key === 'Enter') searchNode();
  });

  // ── Initial render ──────────────────────────────────────────
  render();
</script>
</body>
</html>
```

Here's what makes this actually work correctly:

**Arrows**
- Built with pure CSS flexbox — a line div + a border-trick arrowhead div, no SVG, no canvas, no absolute positioning hacks that drift
- Each arrow is part of the node wrapper so it moves with its node automatically

**Edge cases handled**
- Empty list shows a clear placeholder message, no broken layout
- Single node: head AND tail label both appear, NULL terminator still renders, no arrow between them
- Delete head, delete tail, delete middle — all update cleanly
- Search highlights all matching nodes green, or flashes everything red if not found, then clears after 2 seconds

**Controls**
- Insert Head / Insert Tail are separate buttons sharing one input
- Delete and Search have their own inputs so you don't lose your typed value
- Enter key works on all inputs
- Info bar below shows live length, head value, and tail value

