<body>

<h1>🔗 Linked List Visualizer</h1>

<div class="controls">
  <div class="control-group">
    <label>Value</label>
    <input type="number" id="val-head" placeholder="e.g. 42">
    <button class="btn-insert-head" onclick="insertHead()">Insert Head</button>
  </div>

  <div class="control-group">
    <label>Value</label>
    <input type="number" id="val-tail" placeholder="e.g. 99">
    <button class="btn-insert-tail" onclick="insertTail()">Insert Tail</button>
  </div>

  <div class="control-group">
    <label>Value</label>
    <input type="number" id="val-delete" placeholder="e.g. 5">
    <button class="btn-delete" onclick="deleteNode()">Delete</button>
  </div>

  <div class="control-group">
    <label>Value</label>
    <input type="number" id="val-search" placeholder="e.g. 7">
    <button class="btn-search" onclick="searchNode()">Search</button>
  </div>

  <div class="control-group">
    <button class="btn-clear" onclick="clearList()">Clear List</button>
  </div>
</div>

<div class="message" id="message">List is empty. Insert a node to get started.</div>

<div class="canvas-wrapper">
  <div id="list-container"></div>
  <div class="empty-msg" id="empty-msg">[ empty list ]</div>
</div>

<script>
  // ── Data structure ──────────────────────────────────────────────
  let list = [];          // array of values (simulates linked list)
  let highlightedIdx = null;
  let highlightType  = null; // 'search' | 'found'

  // ── Helpers ─────────────────────────────────────────────────────
  function showMsg(text, type = '') {
    const el = document.getElementById('message');
    el.textContent = text;
    el.className = 'message ' + type;
  }

  function getVal(id) {
    const v = document.getElementById(id).value.trim();
    if (v === '') return null;
    return parseInt(v, 10);
  }

  function clearInput(id) {
    document.getElementById(id).value = '';
  }

  // ── Operations ──────────────────────────────────────────────────
  function insertHead() {
    const v = getVal('val-head');
    if (v === null || isNaN(v)) { showMsg('Please enter a valid number.', 'error'); return; }
    list.unshift(v);
    clearInput('val-head');
    highlightedIdx = 0;
    highlightType  = 'new';
    render();
    showMsg(`Inserted ${v} at head.`, 'success');
    setTimeout(clearHighlight, 1200);
  }

  function insertTail() {
    const v = getVal('val-tail');
    if (v === null || isNaN(v)) { showMsg('Please enter a valid number.', 'error'); return; }
    list.push(v);
    clearInput('val-tail');
    highlightedIdx = list.length - 1;
    highlightType  = 'new';
    render();
    showMsg(`Inserted ${v} at tail.`, 'success');
    setTimeout(clearHighlight, 1200);
  }

  function deleteNode() {
    const v = getVal('val-delete');
    if (v === null || isNaN(v)) { showMsg('Please enter a valid number.', 'error'); return; }
    const idx = list.indexOf(v);
    if (idx === -1) {
      showMsg(`Value ${v} not found in list.`, 'error');
      return;
    }
    list.splice(idx, 1);
    clearInput('val-delete');
    highlightedIdx = null;
    render();
    showMsg(`Deleted node with value ${v}.`, 'success');
  }

  function searchNode() {
    const v = getVal('val-search');
    if (v === null || isNaN(v)) { showMsg('Please enter a valid number.', 'error'); return; }
    clearInput('val-search');

    // animate step by step
    highlightedIdx = 0;
    highlightType  = 'search';
    render();

    let step = 0;
    const target = list.indexOf(v);

    function stepSearch() {
      if (step >= list.length) {
        clearHighlight();
        showMsg(`Value ${v} not found in list.`, 'error');
        return;
      }
      highlightedIdx = step;
      highlightType  = (list[step] === v) ? 'found' : 'search';
      render();

      if (list[step] === v) {
        showMsg(`Found ${v} at index ${step}! ✓`, 'info');
        setTimeout(clearHighlight, 1800);
        return;
      }
      step++;
      setTimeout(stepSearch, 420);
    }

    if (list.length === 0) {
      showMsg('List is empty.', 'error');
      return;
    }
    showMsg(`Searching for ${v}…`, '');
    stepSearch();
  }

  function clearList() {
    list = [];
    highlightedIdx = null;
    render();
    showMsg('List cleared.', '');
  }

  function clearHighlight() {
    highlightedIdx = null;
    highlightType  = null;
    render();
  }

  // ── Render ──────────────────────────────────────────────────────
  function render() {
    const container = document.getElementById('list-container');
    const emptyMsg  = document.getElementById('empty-msg');
    container.innerHTML = '';

    if (list.length === 0) {
      emptyMsg.style.display = 'block';
      return;
    }
    emptyMsg.style.display = 'none';

    list.forEach((val, i) => {
      // wrapper div
      const wrapper = document.createElement('div');
      wrapper.className = 'node-wrapper';

      // node box
      const node = document.createElement('div');
      node.className = 'node';

      if (i === highlightedIdx) {
        if (highlightType === 'found') node.classList.add('found');
        else if (highlightType === 'search') node.classList.add('highlighted');
        else if (highlightType === 'new') node.classList.add('new-node');
      }

      // HEAD label on first node
      if (i === 0) {
        const headLabel = document.createElement('span');
        headLabel.className = 'head-label';
        headLabel.textContent = 'HEAD';
        node.appendChild(headLabel);
      }

      // data cell
      const dataCell = document.createElement('div');
      dataCell.className = 'node-data';
      dataCell.textContent = val;

      // pointer cell
      const ptrCell = document.createElement('div');
      const hasNext = i < list.length - 1;
      ptrCell.className = 'node-ptr' + (hasNext ? ' has-next' : '');
      ptrCell.textContent = hasNext ? 'next' : 'null';

      node.appendChild(dataCell);
      node.appendChild(ptrCell);
      wrapper.appendChild(node);

      // arrow to next node
      if (hasNext) {
        const arrow = document.createElement('div');
        arrow.className = 'arrow';
        arrow.innerHTML = `
          <svg width="44" height="24" viewBox="0 0 44 24" fill="none" xmlns="http://www.w3.org/2000/svg">
            <line x1="0" y1="12" x2="34" y2="12" stroke="#3b82f6" stroke-width="2"/>
            <polygon points="34,6 44,12 34,18" fill="#3b82f6"/>
          </svg>`;
        wrapper.appendChild(arrow);
      }

      // NULL cap after last node
      if (!hasNext) {
        const nullCap = document.createElement('div');
        nullCap.className = 'null-cap';

        // small arrow before NULL
        const arrowToNull = document.createElement('div');
        arrowToNull.className = 'arrow';
        arrowToNull.innerHTML = `
          <svg width="36" height="24" viewBox="0 0 36 24" fill="none" xmlns="http://www.w3.org/2000/svg">
            <line x1="0" y1="12" x2="26" y2="12" stroke="#3a3f5c" stroke-width="2" stroke-dasharray="4 3"/>
            <polygon points="26,6 36,12 26,18" fill="#3a3f5c"/>
          </svg>`;

        const nullBox = document.createElement('div');
        nullBox.className = 'null-box';
        nullBox.textContent = 'NULL';

        nullCap.appendChild(arrowToNull);
        nullCap.appendChild(nullBox);
        wrapper.appendChild(nullCap);
      }

      container.appendChild(wrapper);
    });
  }

  // ── Keyboard shortcuts ──────────────────────────────────────────
  document.getElementById('val-head').addEventListener('keydown', e => { if (e.key === 'Enter') insertHead(); });
  document.getElementById('val-tail').addEventListener('keydown', e => { if (e.key === 'Enter') insertTail(); });
  document.getElementById('val-delete').addEventListener('keydown', e => { if (e.key === 'Enter') deleteNode(); });
  document.getElementById('val-search').addEventListener('keydown', e => { if (e.key === 'Enter') searchNode(); });

  // ── Init ────────────────────────────────────────────────────────
  render();
</script>
</body>
</html>
```

### What this gets right

| Problem | Solution |
|---|---|
| Broken arrows | Pure SVG `<line>` + `<polygon>` drawn inline — no CSS border hacks |
| Janky layout | Flexbox row with `nowrap` + `min-width: max-content`, arrows are fixed-width SVGs |
| Empty state | Dedicated centered message, container hidden until nodes exist |
| Node boxes | Two-cell design (data \| next pointer) with a visible divider, matches textbook diagrams |
| Search | Step-by-step animation with yellow highlight scanning left→right, green on found |
| Insert/Delete | Head label tracks correctly, NULL cap always on the last node |
| Self-contained | Zero dependencies, single file, works offline |
